import{_ as o,o as t,c as i,a0 as n}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"System-Wide Routing","description":"","frontmatter":{},"headers":[],"relativePath":"guide/routing.md","filePath":"guide/routing.md"}'),a={name:"guide/routing.md"};function s(r,e,l,c,d,u){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="system-wide-routing" tabindex="-1">System-Wide Routing <a class="header-anchor" href="#system-wide-routing" aria-label="Permalink to &quot;System-Wide Routing&quot;">​</a></h1><p>To filter ads and trackers, your system&#39;s network traffic must route through BlockGuard&#39;s local DNS listener (<code>127.0.0.1:53</code>).</p><hr><h2 id="🐧-linux-automatic-mode" tabindex="-1">🐧 Linux (Automatic Mode) <a class="header-anchor" href="#🐧-linux-automatic-mode" aria-label="Permalink to &quot;🐧 Linux (Automatic Mode)&quot;">​</a></h2><p>BlockGuard fully supports Linux platforms running <code>systemd-resolved</code> (Fedora, Ubuntu, Debian, Arch, etc.).</p><p>When you run <code>sudo blockguard start</code>, it automatically performs the following:</p><ol><li>Parses your routing table (<code>ip route</code>) to find the active internet interface (e.g., <code>wlo1</code> or <code>eth0</code>).</li><li>Configures <code>systemd-resolved</code> to point the DNS servers list for that interface to <code>127.0.0.1</code>.</li><li>Flushes resolver caches.</li></ol><p>When you run <code>sudo blockguard stop</code>, it:</p><ol><li>Clears <code>127.0.0.1</code> from the interface DNS settings.</li><li>Reverts the link configurations back to default.</li><li>Restarts the <code>systemd-resolved</code> daemon to instantly pull DHCP configurations from NetworkManager.</li></ol><hr><h2 id="🐧-linux-manual-mode" tabindex="-1">🐧 Linux (Manual Mode) <a class="header-anchor" href="#🐧-linux-manual-mode" aria-label="Permalink to &quot;🐧 Linux (Manual Mode)&quot;">​</a></h2><p>If your Linux distribution does not run <code>systemd-resolved</code> (e.g. Alpine Linux, basic server installations, or custom router builds), the automatic setup might warn that <code>resolvectl</code> is missing. In this case, you must manually point your system DNS resolver to localhost.</p><h3 id="option-a-edit-etc-resolv-conf-direct-fast" tabindex="-1">Option A: Edit <code>/etc/resolv.conf</code> (Direct &amp; Fast) <a class="header-anchor" href="#option-a-edit-etc-resolv-conf-direct-fast" aria-label="Permalink to &quot;Option A: Edit `/etc/resolv.conf` (Direct &amp; Fast)&quot;">​</a></h3><p>Open <code>/etc/resolv.conf</code> in your editor with root privileges:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolv.conf</span></span></code></pre></div><p>Replace the existing <code>nameserver</code> lines with:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nameserver 127.0.0.1</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>On many modern Linux distros, <code>/etc/resolv.conf</code> is dynamically managed by NetworkManager or dhcpcd, meaning your edits will be overwritten upon reboot or reconnection. To lock your changes permanently, see Option B.</p></div><h3 id="option-b-configure-dhcpcd-dhclient" tabindex="-1">Option B: Configure dhcpcd / dhclient <a class="header-anchor" href="#option-b-configure-dhcpcd-dhclient" aria-label="Permalink to &quot;Option B: Configure dhcpcd / dhclient&quot;">​</a></h3><p>If your system uses a DHCP client to manage <code>/etc/resolv.conf</code>, configure it to prepend localhost as the primary resolver:</p><ul><li><strong>For <code>dhcpcd</code></strong> (Edit <code>/etc/dhcpcd.conf</code>):<div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>prepend domain_name_servers 127.0.0.1;</span></span></code></pre></div></li><li><strong>For <code>dhclient</code></strong> (Edit <code>/etc/dhcp/dhclient.conf</code>):<div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>prepend domain-name-servers 127.0.0.1;</span></span></code></pre></div></li></ul><hr><h2 id="🍏-macos-manual-configuration" tabindex="-1">🍏 macOS (Manual Configuration) <a class="header-anchor" href="#🍏-macos-manual-configuration" aria-label="Permalink to &quot;🍏 macOS (Manual Configuration)&quot;">​</a></h2><p>On macOS, you must manually point your primary network DNS settings to localhost:</p><ol><li>Open <strong>System Settings</strong> → <strong>Network</strong>.</li><li>Select your active Wi-Fi or Ethernet connection, click <strong>Details...</strong> → <strong>DNS</strong>.</li><li>Click the <strong>+</strong> button under DNS servers, and add: <code>127.0.0.1</code>.</li><li>Remove any other DNS addresses so all queries route through BlockGuard.</li><li>Click <strong>OK</strong> → <strong>Apply</strong>.</li></ol><hr><h2 id="🏁-windows-manual-configuration" tabindex="-1">🏁 Windows (Manual Configuration) <a class="header-anchor" href="#🏁-windows-manual-configuration" aria-label="Permalink to &quot;🏁 Windows (Manual Configuration)&quot;">​</a></h2><p>On Windows, you must configure IPv4 assignment properties:</p><ol><li>Open <strong>Settings</strong> → <strong>Network &amp; internet</strong> → <strong>Wi-Fi</strong> (or <strong>Ethernet</strong>).</li><li>Click <strong>Hardware properties</strong>.</li><li>Under <strong>DNS server assignment</strong>, click <strong>Edit</strong>.</li><li>Choose <strong>Manual</strong>, enable the <strong>IPv4</strong> toggle.</li><li>Enter <code>127.0.0.1</code> in the <strong>Preferred DNS</strong> field.</li><li>Click <strong>Save</strong>.</li></ol>',29)])])}const g=o(a,[["render",s]]);export{h as __pageData,g as default};
